using System.ComponentModel;
using System.Drawing.Design;
using System.Windows.Forms;
using System.Windows.Forms.Design;

public class MyControl : UserControl
{
    private readonly StatusStrip _statusStrip;

    public MyControl()
    {
        _statusStrip = new StatusStrip();
        // .NET 9: StatusStrip default rendering changed.
        // Explicitly set ManagerRenderMode to preserve .NET 8 appearance.
        _statusStrip.RenderMode = ToolStripRenderMode.ManagerRenderMode;
        _statusStrip.Items.Add(new ToolStripStatusLabel("Ready"));
        Controls.Add(_statusStrip);
    }

    [Editor(typeof(SafeDropDownEditor), typeof(UITypeEditor))]
    public string DisplayName { get; set; }

    public int MaxItems { get; set; }
}

public class SafeDropDownEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    public override object? EditValue(
        ITypeDescriptorContext? context, IServiceProvider? provider, object? value)
    {
        if (provider?.GetService(typeof(IWindowsFormsEditorService))
            is not IWindowsFormsEditorService svc)
            return value;

        var picker = BuildPicker(value as string);

        // .NET 9: DropDownControl(null) now throws ArgumentNullException.
        // Guard against null; only call with a valid control instance.
        if (picker is not null)
        {
            svc.DropDownControl(picker);
            return picker.SelectedItem?.ToString() ?? value;
        }

        return value;
    }

    private static ListBox? BuildPicker(string? current)
    {
        var lb = new ListBox();
        lb.Items.AddRange(new object[] { "Option A", "Option B", "Option C" });
        if (current is not null)
            lb.SelectedItem = current;
        return lb;
    }
}

